// // This module selects between two 32-bit inputs, hiDiv and hiMult, based on the value of the selector input. When selector is 0, the output HI will reflect the value of hiMult; when selector is 1, HI will take the value of hiDiv.
module top_module(
	input seletor,
	input [31:0] hiDiv,
	input [31:0] hiMult,
	output  [31:0] HI  
);assign HI = (seletor) ? hiMult : hiDiv;

endmodule
